pub struct Session {
    pub project: String,
    pub project_key: String,
    pub agent_name: String,
    pub broker_url: String,
}

pub struct SessionManager {
    state: Arc<Mutex<Option<Session>>>,
}

impl SessionManager {
    pub fn new() -> Self {
        Self {
            state: Arc::new(Mutex::new(None)),
        }
    }

    /// Set session after successful registration.
    pub fn register(
        &self,
        agent_name: String,
        project: String,
        project_key: String,
        broker_url: String,
    ) {
        save_key(&project, &project_key);
        if let Ok(cwd) = std::env::current_dir() {
            save_identity(&cwd.to_string_lossy(), &agent_name);
        }
        *self.state.lock().unwrap() = Some(Session {
            project,
            project_key,
            agent_name,
            broker_url,
        });
    }

    /// Return (agent_name, project, project_key, broker_url) or an error if not registered.
    pub fn get(&self) -> Result<(String, String, String, String), rmcp::ErrorData> {
        let g = self.state.lock().unwrap();
        match g.as_ref() {
            Some(s) => Ok((
                s.agent_name.clone(),
                s.project.clone(),
                s.project_key.clone(),
                s.broker_url.clone(),
            )),
            None => Err(rmcp::ErrorData::invalid_params(
                "Not registered. Call broker_register first.",
                None,
            )),
        }
    }
}

pub fn key_file_path(project: &str) -> PathBuf {
    let base = dirs::home_dir().unwrap_or_else(|| PathBuf::from("."));
    base.join(".agent-broker").join("keys").join(format!("{project}.key"))
}

pub fn load_key(project: &str) -> Option<String> {
    std::fs::read_to_string(key_file_path(project))
        .ok()
        .map(|s| s.trim().to_string())
}

pub fn save_key(project: &str, key: &str) {
    let path = key_file_path(project);
    if let Some(parent) = path.parent() {
        let _ = std::fs::create_dir_all(parent);
    }
    let _ = std::fs::write(path, key);
}

pub fn identities_path() -> PathBuf {
    let base = dirs::home_dir().unwrap_or_else(|| PathBuf::from("."));
    base.join(".agent-broker").join("identities.json")
}

pub fn load_identities() -> std::collections::HashMap<String, String> {
    std::fs::read_to_string(identities_path())
        .ok()
        .and_then(|s| serde_json::from_str(&s).ok())
        .unwrap_or_default()
}

pub fn save_identity(cwd: &str, name: &str) {
    let mut map = load_identities();
    map.insert(cwd.to_string(), name.to_string());
    let path = identities_path();
    if let Some(parent) = path.parent() {
        let _ = std::fs::create_dir_all(parent);
    }
    let _ = std::fs::write(path, serde_json::to_string_pretty(&map).unwrap_or_default());
}

pub fn lookup_identity() -> Option<String> {
    let cwd = std::env::current_dir().ok()?.to_string_lossy().to_string();
    load_identities().get(&cwd).cloned()
}

pub struct Identity {
    pub name: String,
    pub project: String,
    pub broker_url: String,
}

impl Identity {
    pub fn fq(&self) -> String {
        format!("{}.{}", self.name, self.project)
    }

    /// Load the project key from ~/.agent-broker/keys/<project>.key (shared with the MCP server).
    pub fn project_key(&self) -> Result<String> {
        load_key(&self.project).ok_or_else(|| {
            anyhow!(
                "no project key for '{}'. Run `broker register --as {} ...` first, or place the key at {}",
                self.project,
                self.fq(),
                key_file_path(&self.project).display()
            )
        })
    }

    pub fn ws_url(&self) -> String {
        let base = if let Some(rest) = self.broker_url.strip_prefix("https://") {
            format!("wss://{rest}")
        } else if let Some(rest) = self.broker_url.strip_prefix("http://") {
            format!("ws://{rest}")
        } else {
            format!("ws://{}", self.broker_url)
        };
        format!("{}/ws", base.trim_end_matches('/'))
    }
}

fn base_dir() -> PathBuf {
    dirs::home_dir()
        .unwrap_or_else(|| PathBuf::from("."))
        .join(".agent-broker")
}

fn key_file_path(project: &str) -> PathBuf {
    base_dir().join("keys").join(format!("{project}.key"))
}

fn load_key(project: &str) -> Option<String> {
    std::fs::read_to_string(key_file_path(project))
        .ok()
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty())
}

fn save_key(project: &str, key: &str) {
    let path = key_file_path(project);
    if let Some(parent) = path.parent() {
        let _ = std::fs::create_dir_all(parent);
    }
    let _ = std::fs::write(path, key);
}

fn session_path() -> PathBuf {
    base_dir().join("cli-session.json")
}

fn save_session(id: &Identity) -> Result<()> {
    let path = session_path();
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    std::fs::write(&path, serde_json::to_string_pretty(id)?)?;
    Ok(())
}

fn load_session() -> Option<Identity> {
    let s = std::fs::read_to_string(session_path()).ok()?;
    serde_json::from_str(&s).ok()
}

pub fn parse_as(s: &str) -> Result<(String, String)> {
    let idx = s
        .rfind('.')
        .ok_or_else(|| anyhow!("--as must be Name.Project (e.g. Boss-25435.ClaudeCode)"))?;
    let (name, project) = (&s[..idx], &s[idx + 1..]);
    if name.is_empty() || project.is_empty() {
        bail!("--as must be Name.Project (got '{s}')");
    }
    Ok((name.to_string(), project.to_string()))
}

pub fn resolve(as_flag: Option<&str>, url: &str) -> Result<Identity> {
    if let Some(spec) = as_flag {
        let (name, project) = parse_as(spec)?;
        return Ok(Identity {
            name,
            project,
            broker_url: url.to_string(),
        });
    }
    let mut sess = load_session().ok_or_else(|| {
        anyhow!("no active CLI identity. Pass --as Name.Project or run `broker register` first.")
    })?;
    // CLI/env URL overrides the saved one only if it differs from default resolution.
    if url != DEFAULT_BROKER_URL || std::env::var("BROKER_URL").is_ok() {
        sess.broker_url = url.to_string();
    }
    Ok(sess)
}

pub fn resolve_url(flag: Option<&str>) -> String {
    flag.map(|s| s.to_string())
        .or_else(|| std::env::var("BROKER_URL").ok())
        .unwrap_or_else(|| DEFAULT_BROKER_URL.to_string())
}

struct RegProjResp {
    project_key: String,
}

pub async fn register(
    client: &reqwest::Client,
    name: &str,
    project: &str,
    description: Option<&str>,
    broker_url: &str,
) -> Result<Identity> {
    // Project: register or load existing key on 409.
    let resp = client
        .post(format!("{broker_url}/projects/register"))
        .json(&serde_json::json!({ "name": project }))
        .send()
        .await
        .with_context(|| format!("broker unreachable at {broker_url}"))?;

    let project_key = if resp.status().is_success() {
        resp.json::<RegProjResp>().await?.project_key
    } else if resp.status().as_u16() == 409 {
        load_key(project).ok_or_else(|| {
            anyhow!(
                "project '{project}' already exists but no key at {}. \
                 Place the key there or use a different project.",
                key_file_path(project).display()
            )
        })?
    } else {
        let body = resp.text().await.unwrap_or_default();
        bail!("project registration failed: {body}");
    };

    // Agent.
    let resp = client
        .post(format!("{broker_url}/agents/register"))
        .json(&serde_json::json!({
            "name": name,
            "project": project,
            "project_key": project_key,
            "role": "assistant",
            "description": description.unwrap_or(""),
        }))
        .send()
        .await?;
    if !resp.status().is_success() {
        let body = resp.text().await.unwrap_or_default();
        bail!("agent registration failed: {body}");
    }

    save_key(project, &project_key);
    let id = Identity {
        name: name.to_string(),
        project: project.to_string(),
        broker_url: broker_url.to_string(),
    };
    save_session(&id)?;
    Ok(id)
}

fn attr_re() -> &'static Regex {
    static RE: OnceLock<Regex> = OnceLock::new();
    RE.get_or_init(|| Regex::new(r#"(\w[\w-]*)="([^"]*)""#).unwrap())
}

fn now() -> String {
    chrono::Utc::now().to_rfc3339_opts(chrono::SecondsFormat::Millis, true)
}

fn emit(v: Value) {
    let stdout = std::io::stdout();
    let mut h = stdout.lock();
    let _ = writeln!(h, "{}", serde_json::to_string(&v).unwrap());
    let _ = h.flush();
}

fn stanza_to_json(raw: &str) -> Value {
    let trimmed = raw.trim_start();
    let open_end = trimmed.find('>').unwrap_or(trimmed.len());
    let open = &trimmed[..open_end];

    let mut obj = serde_json::Map::new();
    let event = if trimmed.starts_with("<message") {
        "message"
    } else if trimmed.starts_with("<presence") {
        "presence"
    } else {
        "stanza"
    };
    obj.insert("event".into(), json!(event));
    for cap in attr_re().captures_iter(open) {
        obj.insert(cap[1].to_string(), json!(cap[2].to_string()));
    }
    obj.insert("raw".into(), json!(raw));
    obj.insert("ts".into(), json!(now()));
    Value::Object(obj)
}

async fn session(id: &Identity, key: &str) -> Result<()> {
    let url = id.ws_url();
    let (ws, _) = tokio_tungstenite::connect_async(&url)
        .await
        .with_context(|| format!("ws connect to {url}"))?;
    let (mut tx, mut rx) = ws.split();

    let connect = json!({
        "type": "connect",
        "name": id.name,
        "project": id.project,
        "project_key": key,
    });
    tx.send(Message::Text(connect.to_string().into())).await?;

    while let Some(frame) = rx.next().await {
        let msg = frame?;
        match msg {
            Message::Text(t) => {
                let s = t.as_str();
                if s.trim_start().starts_with('<') {
                    emit(stanza_to_json(s));
                } else if let Ok(env) = serde_json::from_str::<Value>(s) {
                    match env.get("type").and_then(|v| v.as_str()) {
                        Some("connected") => emit(json!({
                            "event": "connected",
                            "as": id.fq(),
                            "session_id": env.get("session_id"),
                            "pending": env.get("pending_count"),
                            "ts": now(),
                        })),
                        Some("error") => {
                            let m = env
                                .get("message")
                                .and_then(|v| v.as_str())
                                .unwrap_or("unknown")
                                .to_string();
                            emit(json!({
                                "event": "error",
                                "message": m,
                                "code": env.get("error_code"),
                                "ts": now(),
                            }));
                            return Err(anyhow!("server error: {m}"));
                        }
                        _ => emit(json!({ "event": "envelope", "raw": s, "ts": now() })),
                    }
                } else {
                    emit(json!({ "event": "text", "raw": s, "ts": now() }));
                }
            }
            Message::Close(c) => {
                emit(json!({
                    "event": "closed",
                    "reason": c.map(|f| f.reason.to_string()),
                    "ts": now(),
                }));
                return Ok(());
            }
            Message::Ping(_) | Message::Pong(_) | Message::Binary(_) | Message::Frame(_) => {}
        }
    }
    emit(json!({ "event": "closed", "reason": null, "ts": now() }));
    Ok(())
}

pub async fn run(id: &Identity, reconnect: bool) -> Result<()> {
    let key = id.project_key()?;
    let mut backoff = 1u64;
    loop {
        match session(id, &key).await {
            Ok(()) if !reconnect => return Ok(()),
            Ok(()) => {
                backoff = 1;
            }
            Err(e) if !reconnect => return Err(e),
            Err(e) => {
                emit(json!({
                    "event": "reconnecting",
                    "error": e.to_string(),
                    "in_secs": backoff,
                    "ts": now(),
                }));
            }
        }
        tokio::time::sleep(tokio::time::Duration::from_secs(backoff)).await;
        backoff = (backoff * 2).min(30);
    }
}

struct Cli {
    /// Act as Name.Project (overrides saved session).
    #[arg(long, global = true, value_name = "NAME.PROJECT")]
    r#as: Option<String>,

    /// Broker base URL (overrides $BROKER_URL; default http://127.0.0.1:4200).
    #[arg(long, global = true)]
    url: Option<String>,

    #[command(subcommand)]
    cmd: Cmd,
}

enum Cmd {
    /// Register Name.Project with the broker and save as the active CLI session.
    Register {
        /// Name.Project (required here; --as is also accepted).
        #[arg(value_name = "NAME.PROJECT")]
        who: Option<String>,
        /// Optional description shown in agent listings.
        #[arg(long)]
        description: Option<String>,
    },
    /// Open a WebSocket and stream incoming stanzas as NDJSON to stdout (run in background).
    Listen {
        /// Reconnect automatically with backoff on disconnect/error.
        #[arg(long, default_value_t = true)]
        reconnect: bool,
        /// Disable auto-reconnect; exit on first close/error.
        #[arg(long, conflicts_with = "reconnect")]
        once: bool,
    },
    /// Send a direct message. Use Name.Project for cross-project targets.
    Dm {
        to: String,
        /// Message body. Omit or pass '-' to read from stdin.
        message: Option<String>,
    },
    /// Post to a channel (#chan or #chan.Project).
    Post {
        channel: String,
        /// Message body. Omit or pass '-' to read from stdin.
        message: Option<String>,
        /// Comma-separated mention list.
        #[arg(long)]
        mentions: Option<String>,
    },
    /// Set presence status.
    Presence {
        #[arg(value_parser = ["available", "busy", "offline"])]
        status: String,
    },
    /// Send a raw stanza XML frame. Reads stdin if XML is omitted or '-'.
    Stanza { xml: Option<String> },
    /// List agents (optionally filtered by project). JSON to stdout.
    Agents {
        #[arg(long)]
        project: Option<String>,
    },
    /// Drain pending messages via HTTP (consumes them). NDJSON to stdout.
    Messages,
    /// Block until at least one message arrives (or timeout). NDJSON to stdout.
    Await {
        /// Total seconds to wait before giving up (exit 2 on timeout).
        #[arg(long, default_value_t = 120)]
        timeout: u64,
        /// Poll interval in seconds.
        #[arg(long, default_value_t = 2)]
        interval: u64,
    },
}

fn read_body(arg: Option<String>) -> Result<String> {
    match arg.as_deref() {
        None | Some("-") => {
            let mut buf = String::new();
            std::io::stdin().read_to_string(&mut buf)?;
            let buf = buf.trim_end_matches(['\r', '\n']).to_string();
            if buf.trim().is_empty() {
                bail!("message body is empty (stdin)");
            }
            Ok(buf)
        }
        Some(s) if s.trim().is_empty() => bail!("message body is empty"),
        Some(s) => Ok(s.to_string()),
    }
}

async fn main() -> Result<()> {
    let cli = Cli::parse();
    let url = resolve_url(cli.url.as_deref());
    let client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(15))
        .build()?;

    match cli.cmd {
        Cmd::Register { who, description } => {
            let spec = who
                .or(cli.r#as.clone())
                .ok_or_else(|| anyhow::anyhow!("register requires NAME.PROJECT (positional or --as)"))?;
            let (name, project) = parse_as(&spec)?;
            let id = identity::register(&client, &name, &project, description.as_deref(), &url).await?;
            eprintln!("registered {} on {}", id.fq(), id.broker_url);
            println!("{}", serde_json::to_string(&id)?);
        }

        Cmd::Listen { once, .. } => {
            let id = resolve(cli.r#as.as_deref(), &url)?;
            listen::run(&id, !once).await?;
        }

        Cmd::Dm { to, message } => {
            let id = resolve(cli.r#as.as_deref(), &url)?;
            let body = read_body(message)?;
            let mid = send::dm(&client, &id, &to, &body).await?;
            println!("{}", serde_json::json!({ "message_id": mid, "to": to }));
        }

        Cmd::Post { channel, message, mentions } => {
            let id = resolve(cli.r#as.as_deref(), &url)?;
            let body = read_body(message)?;
            let mid = send::post(&client, &id, &channel, &body, mentions.as_deref()).await?;
            println!("{}", serde_json::json!({ "message_id": mid, "to": channel }));
        }

        Cmd::Presence { status } => {
            let id = resolve(cli.r#as.as_deref(), &url)?;
            let mid = send::presence(&client, &id, &status).await?;
            println!("{}", serde_json::json!({ "message_id": mid, "status": status }));
        }

        Cmd::Stanza { xml } => {
            let id = resolve(cli.r#as.as_deref(), &url)?;
            let raw = read_body(xml)?;
            let mid = send::stanza(&client, &id, raw).await?;
            println!("{}", serde_json::json!({ "message_id": mid }));
        }

        Cmd::Agents { project } => {
            let list = send::agents(&client, &url, project.as_deref()).await?;
            for a in &list {
                println!(
                    "{}",
                    serde_json::json!({
                        "name": a.name,
                        "project": a.project,
                        "state": a.state,
                        "description": a.description,
                    })
                );
            }
        }

        Cmd::Messages => {
            let id = resolve(cli.r#as.as_deref(), &url)?;
            for m in send::messages(&client, &id).await? {
                println!(
                    "{}",
                    serde_json::json!({
                        "event": "message",
                        "from": format!("{}.{}", m.from_agent, m.from_project),
                        "raw": m.body,

// continued: async fn main() -> Result<()> {
                        "ts": m.created_utc,
                    })
                );
            }
        }

        Cmd::Await { timeout, interval } => {
            let id = resolve(cli.r#as.as_deref(), &url)?;
            let msgs = send::await_messages(&client, &id, timeout, interval).await?;
            if msgs.is_empty() {
                eprintln!("timeout: no messages in {timeout}s");
                std::process::exit(2);
            }
            for m in msgs {
                println!(
                    "{}",
                    serde_json::json!({
                        "event": "message",
                        "from": format!("{}.{}", m.from_agent, m.from_project),
                        "raw": m.body,
                        "ts": m.created_utc,
                    })
                );
            }
        }
    }
    Ok(())
}

