function httpReq(method, port, urlPath, body, headers = {}) {
  return new Promise((resolve, reject) => {
    const data = body != null ? JSON.stringify(body) : null;
    const req = http.request({
      hostname: "localhost", port, path: urlPath, method,
      headers: {
        "Content-Type": "application/json",
        ...(data ? { "Content-Length": Buffer.byteLength(data) } : {}),
        ...headers,
      },
    }, (res) => {
      let buf = "";
      res.on("data", c => buf += c);
      res.on("end", () => {
        try { resolve({ status: res.statusCode, body: JSON.parse(buf) }); }
        catch { resolve({ status: res.statusCode, body: buf }); }
      });
    });
    req.on("error", reject);
    if (data) req.write(data);
    req.end();
  });
}

function httpRaw(port, urlPath, rawBody, headers = {}) {
  return new Promise((resolve, reject) => {
    const data = rawBody ? Buffer.from(rawBody, "utf8") : null;
    const req = http.request({
      hostname: "localhost", port, path: urlPath, method: "POST",
      headers: { ...(data ? { "Content-Length": data.length } : {}), ...headers },
    }, (res) => {
      let buf = "";
      res.on("data", c => buf += c);
      res.on("end", () => resolve({ status: res.statusCode, body: buf }));
    });
    req.on("error", reject);
    if (data) req.write(data);
    req.end();
  });
}

function buildFrame(verb, path, headers = {}, body = "") {
  const bodyBuf = Buffer.from(body, "utf8");
  return `${verb} ${path} HTTP/1.1\r\n` +
    Object.entries(headers).map(([k, v]) => `${k}: ${v}\r\n`).join("") +
    `Content-Length: ${bodyBuf.length}\r\n\r\n${body}`;
}

function parseFrame(text) {
  const crlf = text.indexOf("\r\n");
  const firstLine = text.substring(0, crlf);
  const rest = text.substring(crlf + 2);
  const headerEnd = rest.indexOf("\r\n\r\n");
  const headers = {};
  for (const line of rest.substring(0, headerEnd).split("\r\n")) {
    const i = line.indexOf(":");
    if (i > 0) headers[line.substring(0, i).trim().toLowerCase()] = line.substring(i + 1).trim();
  }
  return { firstLine, headers, body: rest.substring(headerEnd + 4) };
}

async function wsHandshake(identity, privKey, extraHelloHeaders = {}) {
  const ws = await new Promise((res, rej) => {
    const s = new WebSocket(BROKER_WS);
    s.once("open", () => res(s));
    s.once("error", rej);
  });
  ws.send(buildFrame("HELLO", "/v1/sessions", { "X-From": identity, ...extraHelloHeaders }));
  const chalRaw = await nextMsg(ws, 6000);
  const chal = parseFrame(chalRaw);
  if (!chal.firstLine.startsWith("CHALLENGE")) {
    throw new Error(`${identity}: expected CHALLENGE, got: ${chal.firstLine}`);
  }
  const nonce = chal.headers["x-nonce"];
  const payload = Buffer.from(`AITEAM-AUTH-v1\n${identity}\n${nonce}`, "utf8");
  ws.send(buildFrame("AUTH", "/v1/sessions", {
    "X-Sig": crypto.sign(null, payload, privKey).toString("base64"),
  }));
  const authRaw = await nextMsg(ws, 5000);
  const auth = parseFrame(authRaw);
  if (!auth.firstLine.includes("200")) {
    throw new Error(`${identity} AUTH failed: ${auth.firstLine}`);
  }
  return ws;
}

function nextMsg(ws, ms = 6000) {
  return new Promise((res, rej) => {
    const t = setTimeout(() => rej(new Error(`WS timeout ${ms}ms`)), ms);
    ws.once("message", d => { clearTimeout(t); res(d.toString("utf8")); });
  });
}

