pub async fn handle_ws(
    ws: WebSocketUpgrade,
    State(state): State<Arc<AppState>>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_connection(socket, state))
}

async fn send_frame(
    sender: &mut futures::stream::SplitSink<WebSocket, Message>,
    frame: &HttpFrame,
) -> bool {
    sender.send(Message::Text(frame.serialize().into())).await.is_ok()
}

async fn recv_frame(
    receiver: &mut futures::stream::SplitStream<WebSocket>,
) -> Option<HttpFrame> {
    while let Some(next) = receiver.next().await {
        let msg = match next {
            Ok(m) => m,
            Err(e) => {
                tracing::debug!("recv_frame: WS error: {e}");
                return None;
            }
        };
        match msg {
            Message::Text(t) => match http_frame::parse(&t) {
                Ok(f) => return Some(f),
                Err(e) => {
                    tracing::warn!("HttpFrame parse error: {e}");
                    return None;
                }
            },
            Message::Close(_) => return None,
            _ => continue,
        }
    }
    None
}

fn error_response(status: u16, reason: &str) -> HttpFrame {
    HttpFrame::response(status, reason).finalize()
}

fn error_response_with_code(status: u16, code: &str, reason: &str) -> HttpFrame {
    let mut frame = HttpFrame::response(status, reason);
    frame.set_header("X-Error-Code", code);
    frame.finalize()
}

async fn wait_for_handshake(
    sender: &mut futures::stream::SplitSink<WebSocket, Message>,
    receiver: &mut futures::stream::SplitStream<WebSocket>,
    state: &Arc<AppState>,
) -> Option<(String, String)> {
    let frame = recv_frame(receiver).await?;

    // Must be HELLO /v1/sessions
    if frame.verb() != Some("HELLO") || frame.path() != Some("/v1/sessions") {
        if frame.status().is_some() {
            tracing::warn!(
                "Expected HELLO request, received response frame (status {:?})",
                frame.status()
            );
        }
        let _ = send_frame(sender, &error_response_with_code(400, "PROTOCOL_ERROR", "Bad Request")).await;
        return None;
    }

    let xfrom = match frame.header("X-From") {
        Some(v) => v.to_string(),
        None => {
            let _ = send_frame(sender, &error_response(400, "Bad Request")).await;
            return None;
        }
    };

    let (name, project) = match http_frame::parse_identity(&xfrom) {
        Ok((n, p)) => (n.to_string(), p.to_string()),
        Err(_) => {
            let _ = send_frame(sender, &error_response(400, "Bad Request")).await;
            return None;
        }
    };

    let xpubkey = frame.header("X-Pubkey").map(|s| s.to_string());

    if name == "Boards" {
        // TOFU bootstrap rule (spec ┬º6): check for an existing stored key first.
        let stored_hex = state.broker.repo.get_agent_public_key("Boards", &project);
        match stored_hex {
            None => {
                // Token gate (spec ┬º6): TOFU is gated behind a shared secret configured at
                // startup via BOARDS_REGISTRATION_TOKEN. If not configured, TOFU is disabled.
                match &state.config.boards_registration_token {
                    None => {
                        tracing::warn!(
                            "Boards@{} TOFU attempt but BOARDS_REGISTRATION_TOKEN is not configured",
                            project
                        );
                        let _ = send_frame(
                            sender,
                            &error_response_with_code(401, "AUTH_INVALID_TOKEN", "Unauthorized"),
                        )
                        .await;
                        return None;
                    }
                    Some(expected) => {
                        let provided = match frame.header("X-Registration-Token") {
                            Some(t) => t.to_string(),
                            None => {
                                tracing::warn!(
                                    "Boards@{} TOFU missing X-Registration-Token header",
                                    project
                                );
                                let _ = send_frame(
                                    sender,
                                    &error_response_with_code(401, "AUTH_INVALID_TOKEN", "Unauthorized"),
                                )

// continued: async fn wait_for_handshake(
                                .await;
                                return None;
                            }
                        };
                        if provided != *expected {
                            tracing::warn!("Boards@{} TOFU X-Registration-Token mismatch", project);
                            let _ = send_frame(
                                sender,
                                &error_response_with_code(401, "AUTH_INVALID_TOKEN", "Unauthorized"),
                            )
                            .await;
                            return None;
                        }
                    }
                }
                // Token verified ΓÇö X-Pubkey required for first-time registration.
                let pubkey_b64 = match xpubkey {
                    Some(ref k) => k.clone(),
                    None => {
                        tracing::warn!(
                            "Boards HELLO missing X-Pubkey for unregistered Boards@{}",
                            project
                        );
                        let _ = send_frame(sender, &error_response(400, "Bad Request")).await;
                        return None;
                    }
                };
                let pubkey_bytes = match base64::engine::general_purpose::STANDARD.decode(&pubkey_b64) {
                    Ok(b) => b,
                    Err(_) => {
                        let _ = send_frame(sender, &error_response(400, "Bad Request")).await;
                        return None;
                    }
                };
                let pubkey_hex = hex::encode(&pubkey_bytes);
                // Auto-create project if it doesn't exist ΓÇö Boards connects via WS only,
                // there is no separate provisioning step. Use a random sentinel key; Boards
                // never uses project-key auth so no one needs to know it.
                if !state.broker.repo.project_exists(&project) {
                    let sentinel = Uuid::new_v4().to_string();
                    if let Err(e) = state.broker.repo.register_project(&project, &sentinel) {
                        tracing::warn!(
                            "Boards TOFU auto-create project '{}' failed: {}",
                            project,
                            e
                        );
                        let _ = send_frame(sender, &error_response(500, "Internal Server Error")).await;
                        return None;
                    }
                    tracing::info!("Boards@{}: TOFU ΓÇö auto-created project row", project);
                }
                // register_agent is a no-op if row exists (project now guaranteed to exist).
                if let Err(e) = state.broker.repo.register_agent("Boards", &project, "service", "") {
                    tracing::warn!("Boards TOFU register_agent failed for project '{}': {}", project, e);
                    let _ = send_frame(sender, &error_response(403, "Forbidden")).await;

// continued: async fn wait_for_handshake(
                    return None;
                }
                if let Err(e) = state.broker.repo.set_agent_public_key("Boards", &project, &pubkey_hex) {
                    tracing::warn!("Boards TOFU set_agent_public_key failed for project '{}': {}", project, e);
                    let _ = send_frame(sender, &error_response(500, "Internal Server Error")).await;
                    return None;
                }
                tracing::info!("Boards@{}: TOFU ΓÇö first key registered", project);
            }
            Some(stored_hex) => {
                // Key already stored ΓÇö X-Pubkey must be absent or byte-equal. No rotation from wire.
                if let Some(ref wire_b64) = xpubkey {
                    let wire_bytes = match base64::engine::general_purpose::STANDARD.decode(wire_b64) {
                        Ok(b) => b,
                        Err(_) => {
                            let _ = send_frame(sender, &error_response(400, "Bad Request")).await;
                            return None;
                        }
                    };
                    let wire_hex = hex::encode(&wire_bytes);
                    if wire_hex != stored_hex {
                        // Rotation attempt ΓÇö reject BEFORE issuing CHALLENGE (spec ┬º6).
                        tracing::warn!(
                            "Boards@{} key rotation rejected ΓÇö wire X-Pubkey differs from stored key",
                            project
                        );
                        let _ = send_frame(
                            sender,
                            &error_response_with_code(401, "KEY_MISMATCH", "Unauthorized"),
                        )
                        .await;
                        return None;
                    }
                }
                // X-Pubkey absent or byte-equal ΓÇö proceed to CHALLENGE using stored key.
            }
        }
    } else if xpubkey.is_some() {
        // Agent HELLO with X-Pubkey ΓÇö spec ┬º6: MUST ignore, no pubkey rotation from wire.
        tracing::warn!(
            "Agent HELLO from {}@{} carried X-Pubkey ΓÇö ignoring (spec ┬º6: no pubkey rotation from wire)",
            name, project
        );
    }

    // Common path: agent must be registered and have a stored pubkey.
    if !state.broker.repo.agent_exists(&name, &project) {
        tracing::warn!("HELLO from unregistered agent {}@{}", name, project);
        let _ = send_frame(sender, &error_response_with_code(403, "AUTH_INVALID_CREDS", "Forbidden")).await;
        return None;
    }
    let pubkey_hex = match state.broker.repo.get_agent_public_key(&name, &project) {
        Some(k) => k,
        None => {
            tracing::warn!("HELLO from {}@{} ΓÇö no public key registered", name, project);
            let _ = send_frame(sender, &error_response_with_code(403, "AUTH_INVALID_CREDS", "Forbidden")).await;
            return None;
        }
    };

    // Issue challenge
    let identity = format!("{}@{}", name, project);

// continued: async fn wait_for_handshake(
    let (nonce_bytes, nonce_b64, _payload) = state.broker.nonce_store.issue(&identity);
    let nonce_hex = hex::encode(nonce_bytes);

    let challenge = HttpFrame::request("CHALLENGE", "/v1/sessions")
        .add_header("X-Nonce", &nonce_b64)
        .finalize();
    if !send_frame(sender, &challenge).await {
        return None;
    }

    // Receive AUTH
    let auth_frame = recv_frame(receiver).await?;
    if auth_frame.verb() != Some("AUTH") || auth_frame.path() != Some("/v1/sessions") {
        let _ = send_frame(sender, &error_response_with_code(400, "PROTOCOL_ERROR", "Bad Request")).await;
        return None;
    }
    let xsig = match auth_frame.header("X-Sig") {
        Some(s) => s.to_string(),
        None => {
            let _ = send_frame(sender, &error_response(400, "Bad Request")).await;
            return None;
        }
    };

    // Decode X-Sig from base64 ΓåÆ bytes ΓåÆ hex (verify_agent_signature takes hex)
    let sig_bytes = match base64::engine::general_purpose::STANDARD.decode(&xsig) {
        Ok(b) => b,
        Err(_) => {
            let _ = send_frame(sender, &error_response(400, "Bad Request")).await;
            return None;
        }
    };
    let sig_hex = hex::encode(&sig_bytes);

    // Consume nonce ΓÇö retrieves stored canonical payload; None means expired/unknown.
    let payload = match state.broker.nonce_store.consume(&nonce_hex) {
        Some(p) => p,
        None => {
            tracing::warn!("Stale nonce for {}@{}", name, project);
            let _ = send_frame(sender, &error_response_with_code(401, "AUTH_STALE", "Unauthorized")).await;
            return None;
        }
    };

    // Verify ΓÇö verify_strict rejects malleable signatures.
    match crate::identity::verify_agent_signature(&pubkey_hex, &payload, &sig_hex) {
        Ok(()) => {
            tracing::info!("Ed25519 auth: {}@{} authenticated", name, project);
            Some((name, project))
        }
        Err(_) => {
            tracing::warn!("Bad signature from {}@{}", name, project);
            let _ = send_frame(sender, &error_response_with_code(401, "AUTH_WRONG_KEY", "Unauthorized")).await;
            None
        }
    }
}

async fn handle_connection(socket: WebSocket, state: Arc<AppState>) {
    let (mut sender, mut receiver) = socket.split();

    let (name, project) = match wait_for_handshake(&mut sender, &mut receiver, &state).await {
        Some(info) => info,
        None => return, // error already sent in wait_for_handshake
    };

    // Register live session ΓÇö 409 Conflict if same identity already connected.
    let mut rx = match state.broker.connect(&name, &project).await {
        Ok(rx) => rx,
        Err(()) => {
            let _ = send_frame(&mut sender, &error_response_with_code(409, "CONFLICT", "Conflict")).await;
            return;
        }
    };

    // Drain pending messages stored while agent was offline.
    let pending = state.delivery.drain_pending(&name, &project);
    let pending_count = pending.len();

    // Send 200 OK ΓÇö session is open.
    let session_id = uuid::Uuid::new_v4().to_string();
    let ok_frame = HttpFrame::response(200, "OK")
        .add_header("X-Session-Id", &session_id)
        .add_header("X-Pending-Count", &pending_count.to_string())
        .finalize();
    if !send_frame(&mut sender, &ok_frame).await {
        state.broker.disconnect(&name, &project).await;
        return;
    }

    // Send each pending message body as a raw text frame.
    for msg in pending {
        if sender.send(Message::Text(msg.body.into())).await.is_err() {
            state.broker.disconnect(&name, &project).await;
            return;
        }
    }

    // mpsc channel: recv_task sends response frames back to send_task for client delivery.
    let (resp_tx, mut resp_rx) = tokio::sync::mpsc::channel::<String>(8);

    // Send task: forward live messages and response frames to the client.
    let mut send_task = tokio::spawn(async move {
        loop {
            tokio::select! {
                result = rx.recv() => match result {
                    Ok(msg) => {
                        if sender.send(Message::Text(msg.into())).await.is_err() {
                            tracing::warn!("WS send error ΓÇö send_task exiting");
                            break;
                        }
                    }
                    Err(_) => break,
                },
                Some(resp) = resp_rx.recv() => {
                    if sender.send(Message::Text(resp.into())).await.is_err() {
                        tracing::warn!("WS send error on response frame ΓÇö send_task exiting");
                        break;
                    }
                }
            }
        }
    });

    let broker = state.broker.clone();
    let rate_limiter = state.rate_limiter.clone();
    let agent_name = name.clone();
    let agent_project = project.clone();

    // Receive task: parse inbound HttpFrames and dispatch.
    let mut recv_task = tokio::spawn(async move {
        while let Some(Ok(msg)) = receiver.next().await {
            match msg {
                Message::Text(text) => {

// continued: async fn handle_connection(socket: WebSocket, state: Arc<AppState>) {
                    // Rate-limit per project ΓÇö same bucket as HTTP write-path routes.
                    if !rate_limiter.check(&agent_project) {
                        tracing::debug!("WS rate limit exceeded for project '{}'", agent_project);
                        let _ = resp_tx.try_send(error_response(429, "Too Many Requests").serialize());
                        continue;
                    }
                    match http_frame::parse(&text) {
                        Ok(frame) => {
                            handle_inbound(frame, &agent_name, &agent_project, &broker, &resp_tx).await;
                        }
                        Err(e) => {
                            tracing::warn!("HttpFrame parse error from {}@{}: {}", agent_name, agent_project, e);
                            let _ = resp_tx.try_send(
                                error_response_with_code(400, "PARSE_ERROR", "Bad Request").serialize(),
                            );
                        }
                    }
                }
                Message::Close(_) => break,
                _ => {}
            }
        }
    });

    tokio::select! {
        _ = &mut send_task => { recv_task.abort(); }
        _ = &mut recv_task => { send_task.abort(); }
    }

    state.broker.disconnect(&name, &project).await;
    tracing::info!("WebSocket closed: {}@{}", name, project);
}

async fn handle_inbound(
    mut frame: HttpFrame,
    name: &str,
    project: &str,
    broker: &Arc<BrokerState>,
    resp_tx: &tokio::sync::mpsc::Sender<String>,
) {
    let verb = frame.verb().unwrap_or("").to_string();
    let path = frame.path().unwrap_or("").to_string();

    match (verb.as_str(), path.as_str()) {
        ("POST", "/v1/posts") | ("POST", "/v1/reactions") => {
            let xto = match frame.header("X-To").map(|s| s.to_string()) {
                Some(v) => v,
                None => {
                    let _ = resp_tx.try_send(error_response(400, "Bad Request").serialize());
                    return;
                }
            };
            let channel_project = match http_frame::parse_channel(&xto) {
                Ok((_, p)) => p.to_string(),
                Err(_) => {
                    let _ = resp_tx.try_send(error_response(400, "Bad Request").serialize());
                    return;
                }
            };
            // Canonicalize X-From to the authenticated session identity (spec ┬º5).
            // Prevents agents from forging a different sender identity to Boards.
            frame.set_header("X-From", &format!("{}@{}", name, project));
            forward_to_boards(frame, &channel_project, broker, resp_tx).await;
        }
        ("POST", "/v1/dms") => {
            let xto = match frame.header("X-To").map(|s| s.to_string()) {
                Some(v) => v,
                None => {
                    let _ = resp_tx.try_send(error_response(400, "Bad Request").serialize());
                    return;
                }
            };
            let recipient_project = match http_frame::parse_identity(&xto) {
                Ok((_, p)) => p.to_string(),
                Err(_) => {
                    let _ = resp_tx.try_send(error_response(400, "Bad Request").serialize());
                    return;
                }
            };
            // Canonicalize X-From to the authenticated session identity (spec ┬º5).
            // Prevents agents from forging a different sender identity to Boards.
            frame.set_header("X-From", &format!("{}@{}", name, project));
            forward_to_boards(frame, &recipient_project, broker, resp_tx).await;
        }
        ("PUBLISH", "/v1/deliveries") => {
            // Boards-only verb ΓÇö reject from regular agents.
            if name != "Boards" {
                tracing::warn!("PUBLISH rejected from non-Boards agent {}@{}", name, project);
                let _ = resp_tx.try_send(error_response(403, "Forbidden").serialize());
                return;
            }
            let xto = match frame.header("X-To").map(|s| s.to_string()) {
                Some(v) => v,
                None => {
                    let _ = resp_tx.try_send(error_response(400, "Bad Request").serialize());
                    return;
                }
            };
            // Validate all recipients in X-To are valid name@project identities (spec ┬º9).

// continued: async fn handle_inbound(
            if let Err(e) = http_frame::validate_xto_shape("PUBLISH", "/v1/deliveries", &xto) {
                tracing::warn!("PUBLISH X-To invalid from {}@{}: {}", name, project, e);
                let _ = resp_tx.try_send(error_response(400, "Bad Request").serialize());
                return;
            }
            // MUST NOT block the recv loop ΓÇö spawn fan-out.
            let broker_clone = broker.clone();
            tokio::spawn(async move {
                fan_out_publish(frame, xto, &broker_clone).await;
            });
        }
        ("PUT", "/v1/presence") => {
            let status = match frame.header("X-Status").map(|s| s.to_string()) {
                Some(s) => s,
                None => {
                    let _ = resp_tx.try_send(error_response(400, "Bad Request").serialize());
                    return;
                }
            };
            let agent_state = match status.as_str() {
                "available" => AgentState::Available,
                "busy" => AgentState::Busy,
                "offline" => AgentState::Offline,
                _ => {
                    let _ = resp_tx.try_send(error_response(400, "Bad Request").serialize());
                    return;
                }
            };
            broker.set_state(name, project, agent_state).await;
            let _ = resp_tx.try_send(HttpFrame::response(200, "OK").finalize().serialize());
        }
        _ => {
            tracing::warn!("Unknown verb/path from {}@{}: {} {}", name, project, verb, path);
            let _ = resp_tx.try_send(error_response(400, "Bad Request").serialize());
        }
    }
}

async fn forward_to_boards(
    frame: HttpFrame,
    target_project: &str,
    broker: &Arc<BrokerState>,
    resp_tx: &tokio::sync::mpsc::Sender<String>,
) {
    let delivered = broker.send_to_agent("Boards", target_project, &frame.serialize()).await;
    let response = if delivered {
        HttpFrame::response(200, "OK").finalize()
    } else {
        tracing::warn!("Boards@{} not connected ΓÇö 503", target_project);
        let mut r = HttpFrame::response(503, "Service Unavailable").finalize();
        r.set_header("Retry-After", "1");
        r
    };
    let _ = resp_tx.try_send(response.serialize());
}

async fn fan_out_publish(frame: HttpFrame, xto: String, broker: &Arc<BrokerState>) {
    for recipient in xto.split(',') {
        let recipient = recipient.trim();
        if recipient.is_empty() {
            continue;
        }
        let (recv_name, recv_project) = match http_frame::parse_identity(recipient) {
            Ok(r) => r,
            Err(_) => {
                tracing::warn!("PUBLISH fan-out: invalid recipient '{}'", recipient);
                continue;
            }
        };

        // Clone PUBLISH frame and change verb+path to DELIVER; replace X-To with single recipient.
        let mut deliver = frame.clone();
        deliver.first_line = FirstLine::Request {
            verb: "DELIVER".to_string(),
            path: "/v1/deliveries".to_string(),
        };
        deliver.set_header("X-To", recipient);

        let delivered = broker.send_to_agent(recv_name, recv_project, &deliver.serialize()).await;
        if !delivered {
            tracing::debug!(
                "DELIVER to {} not connected ΓÇö dropping (live-only fan-out)",
                recipient
            );
        }
    }
}

async fn spawn_test_server() -> (SocketAddr, Arc<AppState>) {
    spawn_test_server_inner(None).await
}

async fn spawn_test_server_with_boards_token(token: &str) -> (SocketAddr, Arc<AppState>) {
    spawn_test_server_inner(Some(token.to_string())).await
}

async fn spawn_test_server_inner(boards_registration_token: Option<String>) -> (SocketAddr, Arc<AppState>) {
    let repo = Arc::new(db::open_memory().expect("in-memory DB"));
    let broker = Arc::new(BrokerState::new(repo));
    let delivery = Arc::new(DeliveryEngine::new(broker.clone()));
    let config = BrokerConfig { admin_key: None, rate_limit_rps: 100, boards_registration_token };
    let rate_limiter = Arc::new(ProjectRateLimiter::new(100));
    let state = Arc::new(AppState { broker, delivery, config, rate_limiter });

    let listener = tokio::net::TcpListener::bind("127.0.0.1:0")
        .await
        .expect("bind random port");
    let addr = listener.local_addr().expect("local_addr");

    let app = api::http_router(state.clone())
        .route("/ws", axum::routing::get(api::handle_ws))
        .with_state(state.clone());

    tokio::spawn(async move { axum::serve(listener, app).await.ok() });

    (addr, state)
}

type WsStream = tokio_tungstenite::WebSocketStream<
    tokio_tungstenite::MaybeTlsStream<tokio::net::TcpStream>,
>;

async fn ws_connect(addr: SocketAddr) -> WsStream {
    let url = format!("ws://127.0.0.1:{}/ws", addr.port());
    connect_async(url).await.expect("WS connect").0
}

async fn send_frame(ws: &mut WsStream, frame: &HttpFrame) {
    ws.send(WsMsg::Text(frame.serialize().into()))
        .await
        .expect("WS send");
}

async fn recv_frame(ws: &mut WsStream) -> HttpFrame {
    loop {
        let msg = ws.next().await.expect("stream ended").expect("WS recv");
        match msg {
            WsMsg::Text(t) => return http_frame::parse(&t).expect("HttpFrame parse"),
            WsMsg::Close(_) => panic!("connection closed before receiving expected frame"),
            _ => continue,
        }
    }
}

fn setup_agent(state: &Arc<AppState>, project: &str, project_key: &str, agent: &str) -> SigningKey {
    let signing_key = SigningKey::generate(&mut OsRng);
    let pubkey_hex = hex::encode(signing_key.verifying_key().to_bytes());
    state.broker.repo.register_project(project, project_key).expect("register_project");
    state.broker.repo.register_agent(agent, project, "agent", "").expect("register_agent");
    state.broker.repo.set_agent_public_key(agent, project, &pubkey_hex).expect("set_agent_public_key");
    signing_key
}

async fn hello_and_get_challenge(
    ws: &mut WsStream,
    identity: &str,
    xpubkey: Option<&str>,
    xtoken: Option<&str>,
) -> String {
    let mut hello = HttpFrame::request("HELLO", "/v1/sessions").add_header("X-From", identity);
    if let Some(key) = xpubkey {
        hello = hello.add_header("X-Pubkey", key);
    }
    if let Some(token) = xtoken {
        hello = hello.add_header("X-Registration-Token", token);
    }
    let hello = hello.finalize();
    send_frame(ws, &hello).await;

    let challenge = recv_frame(ws).await;
    assert_eq!(
        challenge.verb(),
        Some("CHALLENGE"),
        "expected CHALLENGE frame, got: {:?}",
        challenge.first_line
    );
    challenge.header("X-Nonce").expect("X-Nonce missing in CHALLENGE frame").to_string()
}

fn sign_challenge(signing_key: &SigningKey, identity: &str, nonce_b64: &str) -> String {
    let payload = crate::identity::build_challenge_payload(identity, nonce_b64);
    base64::engine::general_purpose::STANDARD.encode(signing_key.sign(&payload).to_bytes())
}

async fn ws_non_hello_first_frame_sends_protocol_error() {
    let (addr, _state) = spawn_test_server().await;
    let mut ws = ws_connect(addr).await;

    // Send AUTH without first doing HELLO
    let frame = HttpFrame::request("AUTH", "/v1/sessions")
        .add_header("X-Sig", "deadbeef")
        .finalize();
    send_frame(&mut ws, &frame).await;

    let resp = recv_frame(&mut ws).await;
    assert_eq!(resp.status(), Some(400), "expected 400 for protocol violation: {:?}", resp.first_line);
    assert_eq!(
        resp.header("X-Error-Code"),
        Some("PROTOCOL_ERROR"),
        "expected PROTOCOL_ERROR code: {:?}",
        resp
    );
}

async fn ws_expired_nonce_sends_auth_stale() {
    let (addr, state) = spawn_test_server().await;
    let signing_key = setup_agent(&state, "proj-stale", "key-stale", "Alice");
    let identity = "Alice@proj-stale";

    let mut ws = ws_connect(addr).await;
    let nonce_b64 = hello_and_get_challenge(&mut ws, identity, None, None).await;

    // Derive nonce_hex to pre-drain it ΓÇö simulates TTL expiry.
    let nonce_bytes = base64::engine::general_purpose::STANDARD
        .decode(&nonce_b64)
        .expect("nonce b64 decode");
    let nonce_hex = hex::encode(&nonce_bytes);
    let was_present = state.broker.nonce_store.consume(&nonce_hex);
    assert!(was_present.is_some(), "nonce must be in store after challenge issuance");

    // Send a validly-signed AUTH ΓÇö signature is correct, but nonce is gone.
    let sig = sign_challenge(&signing_key, identity, &nonce_b64);
    let auth = HttpFrame::request("AUTH", "/v1/sessions")
        .add_header("X-Sig", &sig)
        .finalize();
    send_frame(&mut ws, &auth).await;

    let resp = recv_frame(&mut ws).await;
    assert_eq!(resp.status(), Some(401), "expected 401 for stale nonce: {:?}", resp.first_line);
    assert_eq!(
        resp.header("X-Error-Code"),
        Some("AUTH_STALE"),
        "expected AUTH_STALE: {:?}",
        resp
    );
}

async fn ws_wrong_key_sends_auth_wrong_key_and_burns_nonce() {
    let (addr, state) = spawn_test_server().await;
    let _correct_key = setup_agent(&state, "proj-badkey", "key-badkey", "Bob");
    let identity = "Bob@proj-badkey";

    let mut ws = ws_connect(addr).await;
    let nonce_b64 = hello_and_get_challenge(&mut ws, identity, None, None).await;

    // Sign with a DIFFERENT key ΓÇö not the registered one.
    let wrong_key = SigningKey::generate(&mut OsRng);
    let sig = sign_challenge(&wrong_key, identity, &nonce_b64);
    let auth = HttpFrame::request("AUTH", "/v1/sessions")
        .add_header("X-Sig", &sig)
        .finalize();
    send_frame(&mut ws, &auth).await;

    let resp = recv_frame(&mut ws).await;
    assert_eq!(resp.status(), Some(401), "expected 401 for wrong key: {:?}", resp.first_line);
    assert_eq!(
        resp.header("X-Error-Code"),
        Some("AUTH_WRONG_KEY"),
        "expected AUTH_WRONG_KEY: {:?}",
        resp
    );

    // Nonce is burned ΓÇö second consume must return None.
    let nonce_bytes = base64::engine::general_purpose::STANDARD
        .decode(&nonce_b64)
        .expect("nonce b64 decode");
    let nonce_hex = hex::encode(&nonce_bytes);
    assert!(
        state.broker.nonce_store.consume(&nonce_hex).is_none(),
        "nonce must be burned after failed verify ΓÇö oracle attack prevention"
    );
}

async fn ws_duplicate_connect_rejected_with_409() {
    let (addr, state) = spawn_test_server().await;
    let signing_key = setup_agent(&state, "proj-dup", "key-dup", "Alice");
    let identity = "Alice@proj-dup";

    // First connection ΓÇö must succeed.
    let mut ws1 = ws_connect(addr).await;
    let nonce1 = hello_and_get_challenge(&mut ws1, identity, None, None).await;
    let sig1 = sign_challenge(&signing_key, identity, &nonce1);
    let auth1 = HttpFrame::request("AUTH", "/v1/sessions")
        .add_header("X-Sig", &sig1)
        .finalize();
    send_frame(&mut ws1, &auth1).await;
    let resp1 = recv_frame(&mut ws1).await;
    assert_eq!(resp1.status(), Some(200), "first connect must succeed: {:?}", resp1.first_line);

    // Second connection ΓÇö same identity, first still active ΓåÆ must get 409.
    let mut ws2 = ws_connect(addr).await;
    let nonce2 = hello_and_get_challenge(&mut ws2, identity, None, None).await;
    let sig2 = sign_challenge(&signing_key, identity, &nonce2);
    let auth2 = HttpFrame::request("AUTH", "/v1/sessions")
        .add_header("X-Sig", &sig2)
        .finalize();
    send_frame(&mut ws2, &auth2).await;
    let resp2 = recv_frame(&mut ws2).await;
    assert_eq!(resp2.status(), Some(409), "second connect must get 409 Conflict: {:?}", resp2.first_line);

