    let agent_ok = recv_frame(&mut agent_ws).await;
    assert_eq!(agent_ok.status(), Some(200), "agent must authenticate: {:?}", agent_ok.first_line);

    // --- Agent sends POST /v1/posts with a forged X-From ---
