pub struct NonceStore {
    inner: RwLock<HashMap<String, (Vec<u8>, Instant)>>,
}

impl NonceStore {
    pub fn new() -> Self {
        Self {
            inner: RwLock::new(HashMap::new()),
        }
    }

    /// Issue a new nonce for the given identity (`name@project`).
    ///
    /// Generates random bytes, encodes as standard base64 for the CHALLENGE X-Nonce header,
    /// builds the canonical challenge payload, and stores it keyed by nonce_hex with a TTL.
    ///
    /// Returns `(nonce_bytes, nonce_b64, canonical_payload)`.
    /// - `nonce_b64` is sent as `X-Nonce` in the CHALLENGE frame.
    /// - `canonical_payload` is the bytes the client must sign.
    /// - The stored payload is retrieved by `consume(nonce_hex)` at verify time.
    pub fn issue(&self, identity: &str) -> ([u8; 32], String, Vec<u8>) {
        let mut nonce = [0u8; 32];
        OsRng.fill_bytes(&mut nonce);

        let nonce_b64 = base64::engine::general_purpose::STANDARD.encode(nonce);
        let payload = crate::identity::build_challenge_payload(identity, &nonce_b64);

        let nonce_hex = hex::encode(nonce);
        let expires_at = Instant::now() + Duration::from_secs(NONCE_TTL_SECS);

        self.inner
            .write()
            .unwrap_or_else(|p| p.into_inner())
            .insert(nonce_hex, (payload.clone(), expires_at));

        (nonce, nonce_b64, payload)
    }

    /// Consume a nonce: return the stored canonical payload if the nonce exists and is not expired.
    /// Removes the nonce from the store regardless (even if expired ΓÇö prevents memory leak).
    /// Returns None if nonce is not found or expired.
    pub fn consume(&self, nonce_hex: &str) -> Option<Vec<u8>> {
        let mut store = self.inner.write().unwrap_or_else(|p| p.into_inner());
        match store.remove(nonce_hex) {
            Some((payload, expires_at)) if Instant::now() <= expires_at => Some(payload),
            _ => None,
        }
    }

    /// Evict all expired nonces. Called periodically from the cleanup loop.
    pub fn evict_expired(&self) {
        let now = Instant::now();
        self.inner
            .write()
            .unwrap_or_else(|p| p.into_inner())
            .retain(|_, (_, expires_at)| *expires_at > now);
    }
}

mod tests {
    use super::*;

    /// `consume()` after a failed verify burns the nonce ΓÇö second attempt returns None.
    ///
    /// Security invariant: the client MUST reconnect for a fresh challenge on any failed auth.
    /// This prevents an attacker from probing multiple signatures against the same nonce.
    #[test]
    fn consume_burns_nonce_regardless_of_verify_outcome() {
        let store = NonceStore::new();
        let (nonce_bytes, _nonce_b64, _payload) = store.issue("Alice@proj");
        let nonce_hex = hex::encode(nonce_bytes);

        // First consume ΓÇö payload returned (caller will attempt verify_agent_signature)
        let first = store.consume(&nonce_hex);
        assert!(first.is_some(), "first consume must return the stored payload");

        // Simulate failed verify: caller got WrongKey, nonce is already gone.
        // Second consume must return None ΓÇö nonce is burned.
        let second = store.consume(&nonce_hex);
        assert!(second.is_none(), "second consume must return None ΓÇö nonce burned on first consume");
    }

    /// `consume()` on an unknown nonce returns None.
    #[test]
    fn consume_unknown_nonce_returns_none() {
        let store = NonceStore::new();
        assert!(store.consume("deadbeef").is_none(), "unknown nonce must return None");
    }

    /// `issue()` + `consume()` round-trip: payload matches.
    #[test]
    fn issue_and_consume_payload_matches() {
        let store = NonceStore::new();
        let (nonce_bytes, _nonce_b64, issued_payload) = store.issue("Bob@my-proj");
        let nonce_hex = hex::encode(nonce_bytes);

        let consumed_payload = store.consume(&nonce_hex).expect("must return payload");
        assert_eq!(consumed_payload, issued_payload, "consumed payload must match issued payload");
    }
}

pub struct AgentSession {
    pub name: String,
    pub project: String,
    pub state: AgentState,
    pub tx: broadcast::Sender<String>,
}

pub enum AgentState {
    #[default]
    Available,
    Busy,
    Offline,
}

impl std::fmt::Display for AgentState {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            AgentState::Available => write!(f, "available"),
            AgentState::Busy => write!(f, "busy"),
            AgentState::Offline => write!(f, "offline"),
        }
    }
}

pub struct AgentKey {
    pub name: String,
    pub project: String,
}

impl AgentKey {
    pub fn new(name: &str, project: &str) -> Self {
        Self {
            name: name.to_string(),
            project: project.to_string(),
        }
    }
}

pub struct BrokerState {
    pub(crate) repo: Arc<Repository>,
    pub sessions: RwLock<HashMap<AgentKey, AgentSession>>,
    /// In-memory nonce store for Ed25519 challenge-response handshakes.
    pub nonce_store: NonceStore,
}

pub fn new(repo: Arc<Repository>) -> Self {
        Self {
            repo,
            sessions: RwLock::new(HashMap::new()),
            nonce_store: NonceStore::new(),
        }
    }

pub async fn connect(
        &self,
        name: &str,
        project: &str,
    ) -> Result<broadcast::Receiver<String>, ()> {
        let key = AgentKey::new(name, project);
        let mut sessions = self.sessions.write().await;
        if sessions.contains_key(&key) {
            tracing::warn!("Duplicate connect rejected: {}.{}", name, project);
            return Err(());
        }
        let (tx, rx) = broadcast::channel(64);
        let session = AgentSession {
            name: name.to_string(),
            project: project.to_string(),
            state: AgentState::Available,
            tx,
        };
        sessions.insert(key, session);
        tracing::info!("Agent connected: {}.{}", name, project);
        Ok(rx)
    }

pub async fn disconnect(&self, name: &str, project: &str) {
        let key = AgentKey::new(name, project);
        let mut sessions = self.sessions.write().await;
        // Force offline before removal ΓÇö spec ┬º13 mandate.
        if let Some(session) = sessions.get_mut(&key) {
            session.state = AgentState::Offline;
        }
        sessions.remove(&key);
        tracing::info!("Agent disconnected: {}.{}", name, project);
    }

pub async fn disconnect_all_in_project(&self, project: &str) {
        let mut sessions = self.sessions.write().await;
        sessions.retain(|key, _| key.project != project);
        tracing::info!("Disconnected all sessions for project '{}'", project);
    }

pub async fn set_state(&self, name: &str, project: &str, state: AgentState) {
        let key = AgentKey::new(name, project);
        let mut sessions = self.sessions.write().await;
        if let Some(session) = sessions.get_mut(&key) {
            session.state = state;
        }
    }

pub async fn list_agents(&self, project_filter: Option<&str>, include_offline: bool) -> Vec<AgentInfo> {
        let sessions = self.sessions.read().await;
        let mut result: Vec<AgentInfo> = sessions
            .values()
            .filter(|s| project_filter.map_or(true, |p| s.project == p))
            .filter(|s| s.name != "Boards") // Boards is a service participant, not an agent
            .map(|s| AgentInfo {
                name: s.name.clone(),
                project: s.project.clone(),
                state: s.state,
                // N DB reads (one per connected agent) ΓÇö acceptable at broker scale.
                // Batch with WHERE name IN (...) if contention becomes an issue.
                description: self.repo.get_agent_description(&s.name, &s.project),
            })
            .collect();

        if include_offline {
            // Build set of connected (name, project) keys to avoid duplicates
            let connected: std::collections::HashSet<(String, String)> =
                result.iter().map(|a| (a.name.clone(), a.project.clone())).collect();
            // Synthesise offline entries for agents in DB but not in sessions
            let registered = self.repo.list_registered_agents(project_filter);
            for (name, project, description) in registered {
                if name == "Boards" { continue; } // service participant, not an agent
                if !connected.contains(&(name.clone(), project.clone())) {
                    result.push(AgentInfo {
                        name,
                        project,
                        state: AgentState::Offline,
                        description,
                    });
                }
            }
        }
        result
    }

pub async fn send_to_agent(&self, name: &str, project: &str, message: &str) -> bool {
        let key = AgentKey::new(name, project);
        let sessions = self.sessions.read().await;
        if let Some(session) = sessions.get(&key) {
            session.tx.send(message.to_string()).is_ok()
        } else {
            false
        }
    }

