    fn register_tool_registered_by_format() {
        let repo = make_repo();
        let entry = repo.register_tool("fmt-tool", "desc", "maintainer", "contact", "Neo", "Matrix").unwrap();
        assert_eq!(entry.registered_by, "Neo.Matrix");
    }

