    fn list_tools_ordered_by_name() {
        let repo = make_repo();
        repo.register_tool("zebra-tool", "z", "", "", "A", "P").unwrap();
        repo.register_tool("alpha-tool", "a", "", "", "A", "P").unwrap();
        let tools = repo.list_tools();
