    fn delete_tool_removes_entry() {
        let repo = make_repo();
        repo.register_tool("temp-tool", "desc", "", "", "A", "P").unwrap();
        repo.delete_tool("temp-tool").unwrap();
        assert!(repo.get_tool("temp-tool").is_none());
    }

